function priceQuoteStep(step: QuoteStep): { premium: number } {
  const policyBase = step.items.reduce(
    (sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0),
    0,
  );
  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
  const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
  return { premium };
}

export function runScenario(scenario: Scenario): {
  results: { premium: number }[];
} {
  const results = scenario.steps.map(priceQuoteStep);
  return { results };
}
